// Quantum Daily P&L Report v3.1 — Fix stop-loss check: queries all open orders + OCO legs.1 — Fix stop-loss check: queries all open orders + OCO legs
// Pulls Alpaca positions, orders, account data.
// Outputs TWO message fields:
//   subscriberMessage — clean professional (no debug lines)
//   personalMessage   — full debug (includes warnings, scanner status)

// Initialize Alpaca keys in this workflow's static data if not set
const _pnlState = $getWorkflowStaticData('global');
if (!_pnlState._alpaca_key) {
  _pnlState._alpaca_key = 'REDACTED_ALPACA_KEY_ID';
  _pnlState._alpaca_secret = 'REDACTED_ALPACA_SECRET';
}
const ALPACA_KEY    = _pnlState._alpaca_key;
const ALPACA_SECRET = _pnlState._alpaca_secret;
const ALPACA_BASE   = 'https://paper-api.alpaca.markets';
const NL = String.fromCharCode(10);

const _self = this;
async function alpaca(path) {
  try {
    return await _self.helpers.httpRequest({
      method: 'GET',
      url: ALPACA_BASE + path,
      headers: { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SECRET },
      json: true,
    });
  } catch (err) {
    console.log('[P&L] Error: ' + path + ' — ' + (err.message || err));
    return null;
  }
}

// Fetch data
const account   = await alpaca('/v2/account');
const positions = await alpaca('/v2/positions') || [];
const todayStr  = new Date().toISOString().split('T')[0];
const allOrders = await alpaca('/v2/orders?status=all&limit=500&after=' + todayStr + 'T00:00:00Z') || [];
// v3.1: Fetch ALL open orders (including those from prior days) with nested legs for stop-loss check
// v3.1: Fetch ALL open orders (including those from prior days) with nested legs for stop-loss check
const allOpenOrders = await alpaca('/v2/orders?status=open&limit=500&nested=true') || [];
// v3.1: Fetch ALL open orders (including those from prior days) with nested legs for stop-loss check

// Date
const dateStr = new Date().toLocaleDateString('en-US', {
  timeZone: 'America/New_York',
  month: 'long',
  day: 'numeric',
  year: 'numeric',
});

if (!account) {
  const errMsg = '\uD83D\uDCCA <b>QUANTUM DAILY P&amp;L REPORT \u2014 ' + dateStr + '</b>' + NL + NL + 'Error: Could not connect to Alpaca.';
  return [{ json: { subscriberMessage: errMsg, personalMessage: errMsg } }];
}

// Account P&L
const equity       = parseFloat(account.equity) || 0;
const lastEquity   = parseFloat(account.last_equity) || 0;
const totalPnL     = equity - lastEquity;
const totalPnLPct  = lastEquity > 0 ? (totalPnL / lastEquity * 100) : 0;

// Unrealized from positions
let unrealizedPnL = 0;
const posData = [];
for (const p of positions) {
  const upl    = parseFloat(p.unrealized_pl) || 0;
  const uplPct = (parseFloat(p.unrealized_plpc) || 0) * 100;
  unrealizedPnL += upl;
  posData.push({ symbol: p.symbol, uplPct });
}

// Realized = Total - Unrealized
const realizedPnL = totalPnL - unrealizedPnL;

// Signals today — count unique tickers from filled bracket entry orders
const filledEntries = allOrders.filter(o =>
  o.status === 'filled' && o.type === 'market' &&
  (o.order_class === 'bracket' || o.order_class === '' || !o.order_class)
);
const buyTickers  = [...new Set(filledEntries.filter(o => o.side === 'buy').map(o => o.symbol))];
const sellTickers = [...new Set(filledEntries.filter(o => o.side === 'sell').map(o => o.symbol))];
const totalSignals = buyTickers.length + sellTickers.length;

// Top 3 performers
const sorted = [...posData].sort((a, b) => b.uplPct - a.uplPct);
const top3   = sorted.slice(0, 3).filter(p => p.uplPct > 0);

// Worst performer
const worst = sorted.length > 0 ? sorted[sorted.length - 1] : null;

// v3.1: GTC bracket check — queries ALL open orders (not just today) + checks OCO legs
let allBracketed = true;
const unprotectedTickers = [];
for (const p of positions) {
  const sym = p.symbol;
  const side = parseFloat(p.qty) >= 0 ? 'long' : 'short';
  const exitSide = side === 'long' ? 'sell' : 'buy';

  let hasStop = false;
  for (const o of allOpenOrders) {
    if (o.symbol !== sym) continue;
    // Check top-level stop orders
    if (o.side === exitSide && (o.type === 'stop' || o.type === 'stop_limit' || o.type === 'trailing_stop')) {
      hasStop = true;
      break;
    }
    // Check OCO/bracket legs
    const legs = o.legs || [];
    for (const leg of legs) {
      if (leg.symbol === sym && leg.side === exitSide && (leg.type === 'stop' || leg.type === 'stop_limit')) {
        hasStop = true;
        break;
      }
    }
    if (hasStop) break;
  }

  if (!hasStop) {
    allBracketed = false;
    unprotectedTickers.push(sym);
  }
}

// Status
let status = 'Healthy';
let icon   = '\u2705';
if (totalPnL < -500)  { status = 'Under Pressure'; icon = '\u26A0\uFE0F'; }
if (totalPnL < -1000) { status = 'Risk Alert';     icon = '\uD83D\uDED1'; }

// Formatters
function fmtD(val) {
  return (val >= 0 ? '+' : '-') + '$' + Math.abs(val).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}
function fmtP(val) {
  return (val >= 0 ? '+' : '') + val.toFixed(2) + '%';
}

// --- Build SHARED core message (used by both channels) ---
let core = '\uD83D\uDCCA <b>QUANTUM DAILY P&amp;L REPORT \u2014 ' + dateStr + '</b>' + NL + NL;

if (totalSignals === 0 && positions.length === 0) {
  core += 'No activity today. No open positions.' + NL;
  core += 'Status: All clear ' + icon;
  return [{ json: { subscriberMessage: core, personalMessage: core } }];
}

core += 'Total Signals: ' + totalSignals + ' (' + buyTickers.length + ' BUY, ' + sellTickers.length + ' SELL)' + NL;
core += 'Realized P&amp;L: ' + fmtD(realizedPnL) + NL;
core += 'Unrealized P&amp;L: ' + fmtD(unrealizedPnL) + NL;
core += 'Total P&amp;L: ' + fmtD(totalPnL) + ' (' + fmtP(totalPnLPct) + ')' + NL + NL;
core += 'Open Positions: ' + positions.length + NL;

if (top3.length > 0) {
  core += 'Top Performers: ' + top3.map(p => p.symbol + ' ' + fmtP(p.uplPct)).join(', ') + NL;
}
if (worst && worst.uplPct < -1) {
  core += 'Worst: ' + worst.symbol + ' ' + fmtP(worst.uplPct) + NL;
}

core += 'Status: ' + status + ' ' + icon + NL;

// --- Subscriber message: clean professional, no debug lines ---
const subscriberMessage = core;

// --- Personal message: full debug with scanner status + warnings ---
let personal = core;
const bracketMsg = allBracketed
  ? 'All ' + positions.length + ' positions protected with stop-loss orders.'
  : 'Warning: ' + unprotectedTickers.length + ' position(s) missing stop-loss: ' + unprotectedTickers.join(', ');
personal += NL + bracketMsg;

const personalMessage = personal;

return [{ json: { subscriberMessage, personalMessage } }];
